import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and processing fee
  it("quote with empty item list yields premium of 5 G (processing fee only)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Quote: single main item base premiums
  it("quote with a single plain sword (newcomer, first contract) yields 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("quote with a single plain amulet yields 65 G (60 base + 5 fee)");
  it.todo("quote with a single plain staff yields 85 G (80 base + 5 fee)");
  it.todo("quote with a single plain potion yields 45 G (40 base + 5 fee)");

  // Quote: components and the block discount
  it.todo("quote with 2 runes yields 55 G (50 base + 5 fee)");
  it.todo("quote with 3 runes applies the block discount: 65 G (60 base + 5 fee)");
  it.todo("quote with 4 runes does not apply the block: 105 G (100 base + 5 fee)");
  it.todo("quote with 7 runes yields 180 G (175 base + 5 fee)");
  it.todo("quote with 2 runes + 1 moonstone yields 80 G (75 base + 5 fee, no block)");
  it.todo("quote with 3 runes + 3 moonstones applies two separate blocks: 125 G (120 base + 5 fee)");

  // Quote: item-specific modifiers
  it.todo("quote with a cursed sword adds a 50% surcharge to that item");
  it.todo("quote with a sword at enchantment 5 adds the 30% high-enchantment surcharge");
  it.todo("quote with a sword at enchantment 4 does not add the high-enchantment surcharge");
  it.todo("quote with a cursed sword at enchantment 5 stacks both surcharges");

  // Quote: policy-wide modifiers
  it.todo("quote for a 2-year customer applies the 20% loyalty discount to the policy");
  it.todo("quote for a brand new customer applies the 10% first-insurance surcharge");
  it.todo("quote for a customer's second contract applies the 15% follow-up discount");

  // Quote: integration examples from the spec
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo("3-year customer's second contract with cursed sword (steel, enchantment 7) → premium 160 G");

  // Quote: multi-item modifier scope
  it.todo("policy with cursed sword and plain amulet → premium 215 G (160 base + 50 curse + 5 fee)");

  // Quote: rounding in MHPCO's favor
  it.todo("premium that yields 197.5 G is rounded up to 198 G");

  // Quote: unknown item type
  it.todo("quote with an unknown item type causes the CLI to exit non-zero with stderr error");

  // Claim: basic reimbursement, deductible, cap
  it.todo("claim on a steel sword (enchantment 3) damage 500 → payout 400 (deductible 100)");
  it.todo("claim on a rune damage 200 → payout 100 (deductible 100)");
  it.todo("claim on a dragon-material sword enchantment 9 damage 1000 → payout 400 (50% then deductible)");
  it.todo("claim on a dragon-material sword enchantment 5 damage 800 → payout 700 (full, then deductible)");
  it.todo("claim on a steel sword enchantment 9 damage 1000 → payout 400 (50% then deductible)");
  it.todo("claim on a dragon-material sword enchantment 8 damage 1000 → payout 400");

  // Claim: deductible per damage event
  it.todo("dragon attack damaging insured sword (500) and amulet (300) → payout 600 (deductible per item)");

  // Claim: cap exhaustion across successive claims
  it.todo("two successive 1500 claims on a sword: first → payout 1400 remainingCap 600; second → payout 600 remainingCap 0");

  // Claim: multiple items of the same type
  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
  it.todo("two sword damages on a policy with only one sword insured → CLI exits non-zero");

  // Claim: error cases
  it.todo("claim referencing an item type not on the policy → CLI exits non-zero with stderr");
  it.todo("claim with negative damage amount → CLI exits non-zero with stderr");

  // Claim: rounding in MHPCO's favor
  it.todo("payout that yields 350.5 G is rounded down to 350 G");
});

