interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const itemBasePremium = (item: Item): number => {
  const base = ITEM_BASE_PREMIUM[item.type];
  // first-insurance surcharge per item (10%)
  return base * 1.1;
};

const ceilToFavor = (n: number): number => Math.ceil(n);

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => {
    const itemSum = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
    const premium = ceilToFavor(itemSum) + 5;
    return { premium };
  });
  return { results };
};

