const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

// Work in hundredths of G to avoid floating-point rounding while still being able to
// represent the percentage modifiers exactly.
const SCALE = 100;

const mainItemBaseScaled = (item: Item): number => {
  const base = MAIN_ITEM_BASE_PREMIUM[item.type] * SCALE;
  // first-insurance surcharge per item (+10%)
  return base + base / 10;
};

const componentsBaseScaled = (items: Item[]): number => {
  // Group components by type, apply block discount per group of 3.
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    const blocks = Math.floor(count / 3);
    const remaining = count % 3;
    // Block: 60 G per block. Remaining: 25 G each.
    const groupBase = blocks * 60 * SCALE + remaining * 25 * SCALE;
    // first-insurance surcharge applies per item
    total += groupBase + groupBase / 10;
  }
  return total;
};

const ceilUpToG = (scaled: number): number => Math.ceil(scaled / SCALE);

export const runScenario = (input: Scenario): { results: Array<{ premium: number }> } => {
  const results = input.steps.map((step) => {
    const mainItems = step.items.filter(isMainItem);
    const components = step.items.filter(isComponent);
    const itemSumScaled =
      mainItems.reduce((sum, item) => sum + mainItemBaseScaled(item), 0) +
      componentsBaseScaled(components);
    const premium = ceilUpToG(itemSumScaled) + 5;
    return { premium };
  });
  return { results };
};

