  let total = 0;
  for (const count of counts.values()) {
    // Block discount applies only when there are exactly 3 components of the same type.
    const groupBase = (count === 3 ? 60 : count * 25) * SCALE;
    // first-insurance surcharge applies per item
    total += groupBase + groupBase / 10;
  }
  return total;
};

