interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

// Work in hundredths of G to avoid floating-point rounding while still being able to
// represent the percentage modifiers exactly.
const SCALE = 100;

const mainItemBaseScaled = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type] * SCALE;

const mainItemSurchargesScaled = (item: Item): number => {
  const base = mainItemBaseScaled(item);
  let surcharge = 0;
  if (item.cursed === true) {
    surcharge += base / 2; // +50%
  }
  if ((item.enchantment ?? 0) >= 5) {
    surcharge += (base * 3) / 10; // +30%
  }
  return surcharge;
};

const componentsBaseScaled = (items: Item[]): number => {
  // Group components by type, apply block discount only when count is exactly 3.
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of counts.values()) {
    total += (count === 3 ? 60 : count * 25) * SCALE;
  }
  return total;
};

const ceilUpToG = (scaled: number): number => Math.ceil(scaled / SCALE);

let contractCountByCustomer = 0; // simple counter across the scenario's quote steps

const quotePremium = (
  step: QuoteStep,
  customer: Customer,
  contractIndex: number,
): number => {
  const mainItems = step.items.filter(isMainItem);
  const components = step.items.filter(isComponent);
  const mainBase = mainItems.reduce((sum, item) => sum + mainItemBaseScaled(item), 0);
  const compBase = componentsBaseScaled(components);
  const policyBase = mainBase + compBase;
  const itemSurcharges = mainItems.reduce((sum, item) => sum + mainItemSurchargesScaled(item), 0);

  // Policy-wide modifiers: each is a % of policyBase.
  let policyMods = 0;
  if (customer.yearsWithMHPCO >= 2) {
    policyMods -= (policyBase * 20) / 100; // -20% loyalty
  }
  if (step.items.length > 0) {
    policyMods += (policyBase * 10) / 100; // +10% first insurance (each item is "first")
  }
  if (contractIndex >= 1) {
    policyMods -= (policyBase * 15) / 100; // -15% follow-up
  }

  const subtotalScaled = policyBase + itemSurcharges + policyMods;
  return ceilUpToG(subtotalScaled) + 5;
};

export const runScenario = (
  input: Scenario,
): { results: Array<{ premium: number }> } => {
  contractCountByCustomer = 0;
  const results = input.steps.map((step) => {
    const premium = quotePremium(step, input.customer, contractCountByCustomer);
    contractCountByCustomer += 1;
    return { premium };
  });
  return { results };
};

